// Script: generar_133_png_chiqui_publico.js
// Escribe los PNG de Chiqui directamente en public/chiqui/
// (mismo metodo que los PNG de panoleta) y actualiza componentes.

const fs = require('fs'); const path = require('path');

function escribirPNG(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, Buffer.from(b64, 'base64'));
  console.log('OK PNG: ' + filePath);
}

function escribirTSX(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, Buffer.from(b64, 'base64').toString('utf8'));
  console.log('OK TSX: ' + filePath);
}

escribirPNG('public/chiqui/chiqui_lupa.png', "");
escribirPNG('public/chiqui/chiqui_lentes.png', "");
escribirPNG('public/chiqui/chiqui_doctor.png', "");
escribirPNG('public/chiqui/chiqui_pregunta.png', "");
escribirTSX('components/ChiquiTeCuenta.tsx', "");
escribirTSX('components/DashboardContenido.tsx', "");
escribirTSX('app/registro-diario/page.tsx', "");
